const shortening={isgd:async function(t){const n="https://is.gd/create.php?format=json&url="+encodeURIComponent(t.trim()),o=await fetch(n),e=await o.json();return e.shorturl},vgd:async function(t){const n="https://v.gd/create.php?format=json&url="+encodeURIComponent(t.trim()),o=await fetch(n),e=await o.json();return e.shorturl},spoome:async function(t){const n="https://spoo.me/",o={method:"POST",headers:{Accept:"application/json","Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams({url:t.trim()})},e=await fetch(n,o),r=await e.json();return r.short_url}};